    description = db.Column(db.String(200), nullable=True)
    due_date = db.Column(db.DateTime, nullable=True)
    completed = db.Column(db.Boolean, default=False)

@app.route('/todos', methods=['GET'])
def get_todos():
    todos = TodoItem.query.all()
    return jsonify([{'id': todo.id, 'title': todo.title, 'description': todo.description, 'due_date': todo.due_date, 'completed': todo.completed} for todo in todos])

@app.route('/todos', methods=['POST'])
def create_todo():
    data = request.json
    new_todo = TodoItem(title=data['title'], description=data.get('description'), due_date=data.get('due_date'))
    db.session.add(new_todo)
    db.session.commit()
    return jsonify({'id': new_todo.id}), 201

@app.route('/todos/<int:todo_id>', methods=['PUT'])
def update_todo(todo_id):
    todo = TodoItem.query.get_or_404(todo_id)
